import { readFileSync } from "node:fs";
import { quote, claim } from "./claim-office.js";

type Step = any;

const scenario = JSON.parse(readFileSync(0, "utf-8"));
const years = scenario.customer.yearsWithMHPCO;
const steps: Step[] = scenario.steps;
const results: any[] = [];
for (const step of steps) {
  if (step.op === "claim") {
    const quoteStep = steps[step.policy];
    results.push(claim({ policy: { items: quoteStep.items }, incident: step.incident }));
  } else {
    results.push(quote({ items: step.items, years, priorContract: false }));
  }
}
process.stdout.write(JSON.stringify({ results }));
